	if !ok {
		t.Fatal("missing 'context' parameter")
	}
	if contextParam.Type != "string" {
		t.Errorf("context.Type = %q, want %q", contextParam.Type, "string")
	}
	if contextParam.Required {
		t.Error("context.Required = true, want false")
	}
}

