func TestExecuteCallAgent_AgentNotAllowed(t *testing.T) {
	call := provider.ToolCall{
		ID:        "test-3",
		Name:      CallAgentToolName,
		Arguments: map[string]string{"agent": "unknown", "task": "do something"},
